#include<bits/stdc++.h>
using namespace std;
#define ll long long
#define dbg(x) cerr<<#x" = "<<(x)<<'\n';
const int mod=100003;
ll n,m;
ll qp(ll x,ll y)
{
	x%=mod;
	ll ans=1;
	while(y)
	{
		if(y%2==1) ans=(ans*x)%mod;
		x=x*x%mod;
		y/=2;
	}
	return ans;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>m>>n;
	cout<<(qp(m,n)-(m*qp(m-1,n-1))%mod+mod)%mod;
	return 0;
}
